#!/usr/bin/env node
/**
 * Builds dist/lattice-default.css — the flattened, zero-config default.
 *
 * Lattice themes are Marp theme files: each declares `@theme <name>` and
 * pulls the engine in BY NAME via `@import 'lattice';`, which only Marp's
 * theme set resolves. That makes a bare theme file unusable as a
 * standalone stylesheet (a browser <link> cannot resolve the import).
 *
 * This generator resolves that import physically: it concatenates the
 * built engine (dist/lattice.css) with the default palette's token
 * blocks (everything AFTER the palette's `@import 'lattice';`), producing
 * a single self-contained file. Tokens come last, so they win by source
 * order — the same cascade contract every theme relies on. A consumer can
 * <link>/import this one file and get a themed deck with no theme
 * selection; to override, load a different palette's tokens after it.
 *
 * The default palette is cuoio (warm leather/cream). Change DEFAULT_THEME
 * to re-bless a different palette.
 *
 * Sibling: tools/build-css.js produces the engine this consumes; the
 * orchestrator (tools/build.js) runs this immediately after it.
 *
 * Usage:
 *   node tools/build-default-bundle.js          # write the bundle
 *   node tools/build-default-bundle.js --check   # CI/stale gate
 */

const fs = require('node:fs');
const path = require('node:path');

const ROOT = path.join(__dirname, '..');
const ENGINE = path.join(ROOT, 'dist', 'lattice.css');
const DEFAULT_THEME = 'cuoio';
const THEME = path.join(ROOT, 'themes', `${DEFAULT_THEME}.css`);
const OUTPUT = path.join(ROOT, 'dist', 'lattice-default.css');

const BANNER = [
  '/* dist/lattice-default.css — GENERATED by tools/build-default-bundle.js.',
  ' * Do not edit by hand.',
  ' *',
  ` * The flattened zero-config default: the engine (dist/lattice.css) plus`,
  ` * the ${DEFAULT_THEME} palette inlined, so this single file renders a themed`,
  ' * deck with no theme selection and can be dropped into a browser via one',
  ' * <link>. Tokens are appended last, so they win by source order; to',
  " * override, load another palette's token block after this file.",
  ' *',
  ' * Re-run `npm run default:build` after changing the engine or the',
  ' * default palette. CI gate: `npm run default:check`.',
  ' */',
  '',
].join('\n');

// Everything after the palette's `@import 'lattice';` — i.e. its token
// blocks, minus the @theme header comment and the name-based import.
function paletteTokens() {
  const css = fs.readFileSync(THEME, 'utf8');
  // Match the real at-rule (line-leading), not a mention inside the
  // theme's header comment (`@import 'lattice'` appears there as prose).
  const m = css.match(/^[ \t]*@import\s+['"]lattice['"]\s*;?/m);
  if (!m) {
    throw new Error(
      `themes/${DEFAULT_THEME}.css has no \`@import 'lattice';\` — cannot locate the token block.`,
    );
  }
  return css.slice(m.index + m[0].length).replace(/^\s+/, '').replace(/\s+$/, '');
}

function bundle() {
  const engine = fs.readFileSync(ENGINE, 'utf8').replace(/\s+$/, '');
  return [
    BANNER,
    engine,
    '',
    `/* === default palette: themes/${DEFAULT_THEME}.css (engine import resolved) === */`,
    paletteTokens(),
    '',
  ].join('\n');
}

function main(argv) {
  if (!fs.existsSync(ENGINE)) {
    process.stderr.write('error: dist/lattice.css not found. Run `npm run css:build` first.\n');
    return 1;
  }
  const fresh = bundle();
  if (argv.includes('--check')) {
    const current = fs.existsSync(OUTPUT) ? fs.readFileSync(OUTPUT, 'utf8') : '';
    if (current === fresh) {
      process.stdout.write('lattice-default.css is up to date.\n');
      return 0;
    }
    process.stderr.write('error: lattice-default.css is stale relative to the engine/default palette.\n');
    process.stderr.write('       Run `npm run default:build` to regenerate.\n');
    return 1;
  }
  fs.mkdirSync(path.dirname(OUTPUT), { recursive: true });
  fs.writeFileSync(OUTPUT, fresh);
  process.stdout.write(`wrote dist/lattice-default.css (${fresh.length.toLocaleString()} bytes, default: ${DEFAULT_THEME})\n`);
  return 0;
}

if (require.main === module) process.exit(main(process.argv.slice(2)));

module.exports = { bundle, main, OUTPUT, DEFAULT_THEME };
